using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class FavoriteRecipeConfiguration : IEntityTypeConfiguration<FavoriteRecipe>{public void Configure(EntityTypeBuilder<FavoriteRecipe> builder){builder.ToTable("favorite_recipes");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("favorite_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.CreatedAt).HasColumnType("timestamp with time zone");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.Recipe).WithMany(r => r.FavoriteRecipes).HasForeignKey(e => e.RecipeId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.RecipeId }).IsUnique();}}
